# XtreamlyTV v0.4.1 CI/build repair
# Run from anywhere inside the XtreamlyTV Git repository.
$ErrorActionPreference = 'Stop'
$RepoRoot = (& git rev-parse --show-toplevel 2>$null).Trim()
if (-not $RepoRoot) { throw 'Run this script from inside the XtreamlyTV Git repository.' }
$RepoRoot = (Resolve-Path $RepoRoot).Path
$WrapperJar = Join-Path $RepoRoot 'apps\android-tv\gradle\wrapper\gradle-wrapper.jar'
if (-not (Test-Path $WrapperJar)) { throw 'gradle-wrapper.jar is missing. Restore the wrapper JAR you already generated and committed before applying this repair.' }
$Timestamp = Get-Date -Format 'yyyyMMdd-HHmmss'
$BackupRoot = Join-Path $RepoRoot ".v041-ci-build-backup-$Timestamp"
$Utf8NoBom = [System.Text.UTF8Encoding]::new($false)
$Files = @{
    '.github\workflows\android-tv.yml' = ''
    '.github\workflows\codeql.yml' = ''
    '.github\workflows\release.yml' = ''
    'apps\android-tv\app\build.gradle.kts' = ''
    'apps\android-tv\build.gradle.kts' = ''
    'apps\android-tv\gradle.properties' = 'b3JnLmdyYWRsZS5qdm1hcmdzPS1YbXgzZyAtRGZpbGUuZW5jb2Rpbmc9VVRGLTgKb3JnLmdyYWRsZS5jYWNoaW5nPXRydWUKb3JnLmdyYWRsZS5wYXJhbGxlbD10cnVlCmFuZHJvaWQudXNlQW5kcm9pZFg9dHJ1ZQphbmRyb2lkLm5vblRyYW5zaXRpdmVSQ2xhc3M9dHJ1ZQprb3RsaW4uY29kZS5zdHlsZT1vZmZpY2lhbAo='
    'apps\android-tv\gradle\wrapper\gradle-wrapper.properties' = ''
    'docs\development\android-tv.md' = ''
    'package.json' = ''
    'scripts\check-android-toolchain.mjs' = ''
}
foreach ($RelativePath in $Files.Keys) {
    $Target = Join-Path $RepoRoot $RelativePath
    if (Test-Path $Target) {
        $Backup = Join-Path $BackupRoot $RelativePath
        New-Item -ItemType Directory -Force -Path (Split-Path $Backup -Parent) | Out-Null
        Copy-Item $Target $Backup -Force
    }
    New-Item -ItemType Directory -Force -Path (Split-Path $Target -Parent) | Out-Null
    $Bytes = [Convert]::FromBase64String($Files[$RelativePath])
    [System.IO.File]::WriteAllBytes($Target, $Bytes)
}
$AppJsPath = Join-Path $RepoRoot 'apps\webos\app\js\app.js'
$AppJs = [System.IO.File]::ReadAllText($AppJsPath)
$Unsafe = 'setTimeout(function () { self.virtualGrid.focusIndex(0); }, 0);'
$Safe = "setTimeout(function () {`n        if (self.virtualGrid) self.virtualGrid.focusIndex(0);`n      }, 0);"
if ($AppJs.Contains($Unsafe)) {
    $Backup = Join-Path $BackupRoot 'apps\webos\app\js\app.js'
    New-Item -ItemType Directory -Force -Path (Split-Path $Backup -Parent) | Out-Null
    Copy-Item $AppJsPath $Backup -Force
    [System.IO.File]::WriteAllText($AppJsPath, $AppJs.Replace($Unsafe, $Safe), $Utf8NoBom)
} elseif (-not $AppJs.Contains('if (self.virtualGrid) self.virtualGrid.focusIndex(0);')) {
    Write-Warning 'The expected webOS focus line was not found; inspect apps/webos/app/js/app.js manually.'
}
Push-Location $RepoRoot
try {
    node scripts/check-android-toolchain.mjs
    if ($LASTEXITCODE -ne 0) { throw 'Android toolchain verification failed.' }
    node scripts/check-versions.mjs
    if ($LASTEXITCODE -ne 0) { throw 'Version verification failed.' }
    node scripts/check-webos.mjs
    if ($LASTEXITCODE -ne 0) { throw 'webOS JavaScript verification failed.' }
}
finally { Pop-Location }
Write-Host ''
Write-Host 'XtreamlyTV v0.4.1 CI/build repair applied.' -ForegroundColor Green
Write-Host "Backup: $BackupRoot"
Write-Host 'Next: review git diff, commit, push main, then rerun GitHub Actions.'